  const imageIndex = index + 1;
  const placeholder1 = `<<${name}>>`;
  const placeholder2 = `<<${name.replace(/[0-9]/g,"")}>>`;

  combinedPrompt = combinedPrompt.replaceAll(placeholder1, `<image:${imageIndex}>`);
  combinedPrompt = combinedPrompt.replaceAll(placeholder2, `<image:${imageIndex}>`);
});

