// 1. CONFIGURATION: Priority list (Female first to avoid "male" in "female" issues)
const MAPPING_RULES = {
  female: ["avatar1_female", "avatar2_female", "female", "woman", "girl", "lady"],
  male: ["avatar1_male", "avatar2_male", "male", "man", "boy", "guy"]
};

const items = $input.all();

return items.map(item => {
  const data = item.json;
  const validNames = data["Avatar Names"] || [];

  // Get the correct IDs from the input list
  const correctMale = validNames.find(n => n.toLowerCase().includes('male')) || "Avatar_Male";
  const correctFemale = validNames.find(n => n.toLowerCase().includes('female')) || "Avatar_Female";

  const rectifyText = (text) => {
    if (typeof text !== 'string') return text;

    let processed = text;

    // STEP A: Fix existing <<tags>> first
    processed = processed.replace(/<<([^>>]+)>>/g, (match, p1) => {
      const lower = p1.toLowerCase().trim();
      if (MAPPING_RULES.female.some(f => lower.includes(f))) return `<<${correctFemale}>>`;
      if (MAPPING_RULES.male.some(m => lower.includes(m))) return `<<${correctMale}>>`;
      return match;
    });

    // STEP B: Replace "naked" words and wrap them in << >>
    // We use \b to ensure we only match whole words (stops "human" becoming "hu<<Avatar_Male>>")

    // Check Female words first
    MAPPING_RULES.female.forEach(word => {
      const regex = new RegExp(`\\b${word}\\b`, 'gi');
      processed = processed.replace(regex, `<<${correctFemale}>>`);
    });

    // Check Male words second
    MAPPING_RULES.male.forEach(word => {
      const regex = new RegExp(`\\b${word}\\b`, 'gi');
      processed = processed.replace(regex, `<<${correctMale}>>`);
    });

    // STEP C: Clean up any accidental double-nesting (e.g., << <<Avatar>> >>)
    return processed.replace(/<<\s*<<([^>>]+)>>\s*>>/g, '<<$1>>');
  };

  // 2. APPLY TO ALL FIELDS
  data.MasterShot = rectifyText(data.MasterShot);
  data.ClothingDetails = rectifyText(data.ClothingDetails);
  data.LocationDetails = rectifyText(data.LocationDetails);

  if (Array.isArray(data.StoryShots)) {
    data.StoryShots = data.StoryShots.map(shot => ({
      ...shot,
      framePrompt: rectifyText(shot.framePrompt),
      cameraAndActionPrompt: rectifyText(shot.cameraAndActionPrompt)
    }));
  }

  return { json: data };
});

